class PaymentService {
  Future<void> init() async {
    // Initialize In-App Purchase
    final isAvailable = await InAppPurchase.instance.isAvailable();
    if (!isAvailable) {
      throw Exception('In-app purchases are not available');
    }
  }

  Future<List<ProductDetails>> fetchProducts() async {
    const Set<String> _kIds = {'product_id_1', 'product_id_2'};
    final ProductDetailsResponse response = await InAppPurchase.instance
        .queryProductDetails(_kIds);
    if (response.notFoundIDs.isNotEmpty) {
      throw Exception('Products not found');
    }
    return response.productDetails;
  }

  Future<void> purchaseProduct(ProductDetails product) async {
    final PurchaseParam purchaseParam = PurchaseParam(productDetails: product);
    await InAppPurchase.instance.buyConsumable(purchaseParam: purchaseParam);
  }

  Future<void> processStripePayment(String paymentMethodId) async {
    Stripe.publishableKey = 'your_publishable_key';
    await Stripe.instance.applySettings();

    try {
      final paymentIntentData = await createPaymentIntent(paymentMethodId);
      await Stripe.instance.confirmPayment(paymentIntentData['client_secret']);
    } catch (e) {
      throw Exception('Payment failed: $e');
    }
  }

  Future<Map<String, dynamic>> createPaymentIntent(String paymentMethodId) async {
    // Call your backend to create a payment intent and return the client_secret
    // Example: final response = await http.post(...);
    return {'client_secret': 'your_client_secret'};
  }
}

class PaymentScreen extends StatelessWidget {
  final PaymentService paymentService = PaymentService();

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Payment')),
      body: Center(
        child: FutureBuilder<List<ProductDetails>>(
          future: paymentService.fetchProducts(),
          builder: (context, snapshot) {
            if (snapshot.connectionState == ConnectionState.waiting) {
              return CircularProgressIndicator();
            }
            if (snapshot.hasError) {
              return Text('Error: ${snapshot.error}');
            }
            final products = snapshot.data!;
            return ListView.builder(
              itemCount: products.length,
              itemBuilder: (context, index) {
                final product = products[index];
                return ListTile(
                  title: Text(product.title),
                  subtitle: Text(product.description),
                  trailing: TextButton(
                    onPressed: () => paymentService.purchaseProduct(product),
                    child: Text(product.price),
                  ),
                );
              },
            );
          },
        ),
      ),
    );
  }
}